var e=JSON.parse(`[{"id":"L3_1","type":"dialog","speaker":"KNIGHT_NPC_NULL_NULL","text":{"KOREA":"저, 저기 봐! 구원 기사단이 있는 곳으로 괴수들이 몰려들고 있어!","JPN":"あ、あれを見ろ！　救世騎士団のところに怪獣が集まっている！","ENG":"L-look! The monsters are rushing towards the Knights of Redemption!","TWN":"看，看那邊！怪獸正在湧向救贖騎士團那裡！"},"stage":{"bg":"COUNTERSIDE_ASH","slots":{"L":{"char_id":"KNIGHT_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":"KNIGHT_NPC_NULL_NULL","text":{"KOREA":"어마어마하게 많아……! 저 많은 수를 어떻게 감당하는 거지?","JPN":"なんて数だ……！　あれをどう相手するっていうんだ？","ENG":"The numbers are huge...! How are they going to deal with all of them?","TWN":"太，太多了……！要怎麼對付那麼多怪獸啊？"},"stage":{"bg":"COUNTERSIDE_ASH","slots":{"L":null,"C":null,"R":{"char_id":"KNIGHT_NPC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L6_1","type":"dialog","speaker":"ALLEN_ORDER_NULL_NULL","text":{"KOREA":"좌익이 앞서고 있다! 대열을 유지하도록!","JPN":"左翼が前に出すぎだ！　隊列を維持しろ！","ENG":"Left wing! Keep to your positions!","TWN":"左翼打頭陣！保持隊形！"},"stage":{"bg":"COUNTERSIDE_ASH","slots":{"L":null,"C":{"char_id":"ALLEN_ORDER_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"ALLEN_ORDER_NULL_NULL","text":{"KOREA":"작전의 성공을 위해선 반드시 양익의 전력을 보존해야 한다!","JPN":"作戦成功のためには、必ず両翼の戦力を保たねばならない！","ENG":"We must equally preserve forces on both wings to make this plan work!","TWN":"為了作戰成功，必須保存二翼的戰鬥力！"},"stage":{"bg":"COUNTERSIDE_ASH","slots":{"L":null,"C":{"char_id":"ALLEN_ORDER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"RAY_SCHOOL_NPC_B","text":{"KOREA":"조심해, 알렌!","JPN":"気を付けて、アレン！","ENG":"Allen, watch out!","TWN":"小心，艾倫！"},"stage":{"bg":"COUNTERSIDE_ASH","slots":{"L":{"char_id":"RAY_SCHOOL_NPC_B","face":"UNIT_SERIOUS"},"C":{"char_id":"ALLEN_ORDER_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"ALLEN_ORDER_NULL_NULL","text":{"KOREA":"비행형 괴수로군. 어느 틈에 여기까지…….","JPN":"飛行型の怪獣か、いつの間にここまで……","ENG":"A flying monster? When did it...","TWN":"是飛行類怪獸。什麼時候……"},"stage":{"bg":"COUNTERSIDE_ASH","slots":{"L":null,"C":{"char_id":"ALLEN_ORDER_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"RAY_SCHOOL_NPC_B","text":{"KOREA":"방금은 아슬아슬했어. 지휘도 집중하는 것도 좋지만 주위에도 신경 써 줘.","JPN":"今のは危なかったよ。指揮も大事だけど、周りにも気を配って。","ENG":"That was close. Focusing on your job is good, but don’t forget to look out for yourself.","TWN":"剛才很驚險。集中注意力指揮固然好，但也要注意周圍。"},"stage":{"bg":"COUNTERSIDE_ASH","slots":{"L":null,"C":{"char_id":"RAY_SCHOOL_NPC_B","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"ALLEN_ORDER_NULL_NULL","text":{"KOREA":"새겨 듣지. 대신 요격해 줘서 고맙다.","JPN":"肝に銘じよう。代わりに倒してくれて感謝する。","ENG":"I'll keep that in mind. Thank you for the backup.","TWN":"我會銘記在心的，謝謝你……"},"stage":{"bg":"COUNTERSIDE_ASH","slots":{"L":null,"C":{"char_id":"ALLEN_ORDER_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"CHARLOTTE_ORDER_NULL_NULL","text":{"KOREA":"전하, 남서쪽 방향에서 비행형 괴수들이 다수 접근 중입니다.","JPN":"殿下、南西側から飛行型の怪獣が多数接近中です。","ENG":"Your Highness, multiple flying monsters are approaching from the Southwest direction.","TWN":"殿下，西南方向有多隻飛行類怪獸正在靠近。"},"stage":{"bg":"COUNTERSIDE_ASH","slots":{"L":{"char_id":"CHARLOTTE_ORDER_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":"흠. 예상대로 저항이 거센가. 이 기회에 끝장을 내겠다는 심산이로군.","JPN":"ふむ。予想通りの激しい抵抗だ。ここで片を付けるつもりか。","ENG":"Hmm. Resistance is strong, as presumed. It seems like they're going to end things here for good.","TWN":"嗯，反抗和預想的一樣激烈嗎。看來是想借此機會做個了斷啊。"},"stage":{"bg":"COUNTERSIDE_ASH","slots":{"L":{"char_id":"CHARLOTTE_ORDER_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L19_1","type":"dialog","speaker":"HOLY_KNIGHT_NULL_NULL","text":{"KOREA":"사제들도 전부 탈진 직전입니다.","JPN":"司祭たちも疲れ果てています。","ENG":"The priests are exhausted.","TWN":"祭司也全都快虛脫了。"},"stage":{"bg":"COUNTERSIDE_ASH","slots":{"L":null,"C":{"char_id":"HOLY_KNIGHT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"HOLY_KNIGHT_NULL_NULL","text":{"KOREA":"부상자들을 더 돌보기에는 손이 부족해요.","JPN":"これ以上負傷者が出れば、手が足りなくなります。","ENG":"There's not enough manpower to take care of casualties.","TWN":"照顧傷患的人手也不夠。"},"stage":{"bg":"COUNTERSIDE_ASH","slots":{"L":null,"C":{"char_id":"HOLY_KNIGHT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":"샬롯, 적의 동향이 추가로 감지되진 않았나?","JPN":"シャーロット、敵の動きに進展は？","ENG":"Carlota, any more signs of the enemy?","TWN":"夏洛特，後續有發現敵人的動向嗎？"},"stage":{"bg":"COUNTERSIDE_ASH","slots":{"L":{"char_id":"CHARLOTTE_ORDER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L24_1","type":"dialog","speaker":"CHARLOTTE_ORDER_NULL_NULL","text":{"KOREA":"정찰병들의 보고에 따르면 방금 증원이 이 일대에 있는 마지막 전력입니다.","JPN":"偵察兵の報告によると、先の増援がここら一帯の最後の戦力だったようです。","ENG":"Scout reports show that the recent wave of enemies were the last forces in the area.","TWN":"根據偵察兵的報告，剛才的增援是這一帶最後的戰鬥力。"},"stage":{"bg":"COUNTERSIDE_ASH","slots":{"L":{"char_id":"CHARLOTTE_ORDER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L25_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":"그렇겠지. 저것들에게 구원 기사단은 눈엣가시 같은 존재였으니 말이다.","JPN":"やはりな。奴らにとって救世騎士団は最も厄介な存在だ。","ENG":"I assume so. The Knights of Redemption would be a pain for them.","TWN":"我想也是。對於他們來說，救贖騎士團就是眼中釘一般的存在。"},"stage":{"bg":"COUNTERSIDE_ASH","slots":{"L":{"char_id":"CHARLOTTE_ORDER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_PRIDE"}}}}]`);export{e as default};